import { useStripe } from '@stripe/stripe-react-native';
import { ApplePayButton } from '@stripe/stripe-react-native';

const ApplePayPayment = ({ amount, onSuccess }) => {
  const { presentApplePay, confirmApplePayPayment } = useStripe();

  const handleApplePay = async () => {
    const { error, paymentIntent } = await fetchPaymentIntent(amount);
    if (error) return showToast('Erreur de paiement');

    const { error: appleError } = await presentApplePay({
      cartItems: [{ label: 'Total', amount: amount.toString() }],
      country: 'CM',
      currency: 'XAF',
      paymentIntentClientSecret: paymentIntent.clientSecret,
    });

    if (appleError) return showToast(appleError.message);

    const { error: confirmError } = await confirmApplePayPayment(paymentIntent.clientSecret);
    if (confirmError) showToast(confirmError.message);
    else onSuccess();
  };

  return <ApplePayButton onPress={handleApplePay} type="pay" style={{ width: '100%', height: 48 }} />;
};
