const PaymentMethodSelector = ({ amount, onPaymentComplete }) => {
  const [isGooglePayReady, setIsGooglePayReady] = useState(false);
  const [isApplePayReady, setIsApplePayReady] = useState(false);

  useEffect(() => {
    const checkWallets = async () => {
      if (Platform.OS === 'android') {
        const isReady = await GooglePay.isReadyToPay();
        setIsGooglePayReady(isReady);
      } else if (Platform.OS === 'ios') {
        const isReady = await ApplePay.canMakePayments();
        setIsApplePayReady(isReady);
      }
    };
    checkWallets();
  }, []);

  if (Platform.OS === 'ios' && isApplePayReady) {
    return <ApplePayButton onSuccess={onPaymentComplete} />;
  }
  if (Platform.OS === 'android' && isGooglePayReady) {
    return <GooglePayButton onSuccess={onPaymentComplete} />;
  }
  return <CardPaymentForm onSuccess={onPaymentComplete} />;
};
