const handleGooglePay = async () => {
  try {
    const paymentData = await GooglePay.loadPaymentData(request);
    const response = await processPayment(paymentData);
    if (response.success) {
      navigation.navigate('Success');
    }
  } catch (error) {
    console.log('Erreur Google Pay:', error);

    if (error.code === 'CANCELED') {
      // L'utilisateur a annulé
      return;
    } else if (error.code === 'PAYMENT_FAILED') {
      Alert.alert(
        'Paiement échoué',
        'Votre carte a été refusée. Souhaitez-vous réessayer avec une autre carte ou payer par carte bancaire ?',
        [
          { text: 'Réessayer', onPress: () => handleGooglePay() },
          { text: 'Carte bancaire', onPress: () => setShowCardForm(true) },
          { text: 'Annuler', style: 'cancel' }
        ]
      );
    } else {
      showToast('Une erreur est survenue');
      setShowCardForm(true); // Fallback final
    }
  }
};
